import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;

class CSVFormatTest {

    private enum TestEnum {
        ONE, TWO, THREE
    }

    @Test
    void testWithHeaderWithNull() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeader((Class<? extends Enum<?>>) null);
        assertNotNull(result);
        assertArrayEquals(null, result.getHeader());
    }

    @Test
    void testWithHeaderWithEnum() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeader(TestEnum.class);
        assertNotNull(result);
        String[] expected = {"ONE", "TWO", "THREE"};
        assertArrayEquals(expected, result.getHeader());
    }

    @Test
    void testWithHeaderInvokesPrivateWithHeaderArray() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        String[] headerArray = new String[]{"A", "B"};

        // Use reflection to get private withHeader(String[] header) method
        Method withHeaderArrayMethod = CSVFormat.class.getDeclaredMethod("withHeader", String[].class);
        withHeaderArrayMethod.setAccessible(true);

        // Invoke private method directly and verify new CSVFormat has correct header
        CSVFormat newFormat = (CSVFormat) withHeaderArrayMethod.invoke(format, (Object) headerArray);
        assertNotNull(newFormat);
        assertArrayEquals(headerArray, newFormat.getHeader());
    }
}
